/*-----------------------------------------
   FUNÇÃO QUE VALIDA OS CIDS APRESENTADOS  
   NAS DUAS ABRANGENCIAS!
  ----------------------------------------- */
Definir Alfa lAbrTmp;
Definir Alfa lStrA;
Definir Alfa lStrB;
Definir Alfa EAbrCid;
Definir Alfa EAbrOut;
