Funcao ValidaCID (Numero End NumCID, Numero End Valida);
{
  NumCid = 0;
  Valida = 0;
  lStrA = EAbrCid;

  TamanhoAlfa (lStrA, lTam);

  lind = 1;
  lTotCid = 0;
  Enquanto (lind < 19)
  {
    lAbrTmp = lStrA;
    TiraEspacos (lAbrTmp, lStrA);

    PosicaoAlfa (",", lStrA, lPos);
    lStrB = lStrA;
    /* AINDA HA CIDS E AINDA NAO EXISTEM 18 ITENS... */
    Se ((lPos <> 0) e (lind < 18))
    {
      CopiarAlfa (lStrB, 2, lPos-3);
      CopiarAlfa (lStrA, lPos+1, lTam);
    }
    Senao
    {
      lAbrTmp = lStrB;
      TiraEspacos (lAbrTmp, lStrB);

      CopiarAlfa (lStrB, 2, lTam-2);
      lTotCid = lInd;

      /* VERIFICA SE EXISTEM MAIS DE 18 CODIGOS */
      Se ((lind >= 18) e (lPos <> 0))
        NumCid = 1;
    }
    TCid[lind].xCodCid = lStrB;

    /* ACABOU OS CIDs */
    Se (lTotCid = lInd)
    {
      TCid[lind+1].xCodCid = "Outros";
      TCid[lind+2].xCodCid = "Total";
      lInd = 20;
    }

    lind = lind + 1;
    TamanhoAlfa (lStrA, lTam);
  }


  Se (NumCid <> 1)
  {
    /* COMPARA AS DUAS ABRANGENCIAS */
    lStrA = EAbrOut;

    TamanhoAlfa (lStrA, lTam);

    Enquanto (lTam > 4)
    {
      PosicaoAlfa (",", lStrA, lPos);
      lStrB = lStrA;
      Se (lPos <> 0)
      {
        lAbrTmp = lStrB;
        TiraEspacos (lAbrTmp, lStrB);
        CopiarAlfa (lStrB, 2, lPos-3);
        CopiarAlfa (lStrA, lPos+1, lTam);
        TamanhoAlfa (lStrA, lTam);
      }
      Senao
      {
        lAbrTmp = lStrB;
        TiraEspacos (lAbrTmp, lStrB);
        CopiarAlfa (lStrB, 2, lTam-2);
        lTam = 1;
      }

      /* VERIFICA A EXISTENCIA DO ITEM */
      lind = 1;
      Enquanto (lind < 19)
      {
        Se (TCid[lind].xCodCid = lStrB)
        {
          lind = 18;
          Valida = 1;
        }
        lind = lind + 1;
      }
    }
  }

}

