bands.onAfterPrint:
/************************************************************************
Esse modelo de absenteísmo lista as ocorrências de 15 dias de atestado e 
na 16º ocorrência lista a quantidade de atestados em horas. Ele é listado
assim: para cada dia lista a quantidade de afastamentos naquele dia e na
16º ocorrência lista a quantidade de afastamento em horas. O toal de afastamentos
é o somatório dos afastamentos em dia e afastamentos em horas. E a Qtd. de
Dias Afast. são o total de dias afastados e a Qtd. Horas Afast. são o total
de horas afastadas. O Afastamento de dias e Horas são listados na seção:
Adicional_Dias. Existe nas abrangências a abrangência de CID que se for 
informada, lista de acordo com o CID informado.
*************************************************************************/

AlteraControle ("DTotHor", "Imprimir", "Falso");

ind = 1;
Enquanto (ind < 17)
  {

  Se (ind < 16)
    FNumDia = ind;
  Senao
    {
    FNumDia = 0;
    AlteraControle ("FNumDia", "Imprimir", "Falso");
    AlteraControle ("DTotHor", "Imprimir", "Verdadeiro");
    }

  ZeraValores();

  xTotal = 0;
  xHoras = 0;
  xTotHor = 0;

  Se (ind = 16)
    xdia = 1;
  Senao
    xdia = ind;

  /*********************************
      AFASTAMENTOS - ATENDIMENTOS
   *********************************/

  Se (EncMat = 1)
    {
    sql_abrcid = " 1=1 ";
    /* PROCURA PELOS CIDS A CONSIDERAR */
    EstaNulo (EAbrCid, cid_estanulo);
    Se (cid_estanulo = 0)
      MontaAbrangencia ("R110MAT.CODDOE", EAbrCid , sql_abrcid);

    sql_abrcid = " AND " + sql_abrcid;                  /* ABRANGENCIA */
    sql_abrcid = " AND " + lSQLWhere + sql_abrcid;       /* DATA REFERENCIA */

    CMat.SQL "SELECT CODDOE, HORAFA, HORTER FROM R110MAT WHERE DIAATE = :xdia __Inserir(:sql_abrcid) ORDER BY 2,1";
    CMat.AbrirCursor();

    /* ADICIONARA A TODOS OS CAMPOS OS DIAS DE AFASTAMENTO */
    Enquanto (CMat.Achou)
      {
      /* PROCURAR O CAMPO A SER INFORMADO */
      xind = 1;
      Enquanto (xind <= lTotCid)
        {
        Se (TCid[xind].xCodCid = CMat.CodDoe)
          {
          /* SE FOR APENAS 1 DIA, ENTAO CALCULA AS HORAS */
          Se (ind = 16)
            GetHoras (CMat.HorAfa, CMat.HorTer, xHoras);

          /* SE FOR APENAS 1 DIA NÃO CONTABILIZA PARA DIAS, SOMENTE CONTABILIZA EM HORAS */
          Se (ind < 16)
          {
            Se (xdia > 1)
              AddValor (xind, xdia, 1);
          }
          Senao
            {
            AddValor (xind, 0, 1);
            TotalizaHoras(xind, xHoras);
            }

          xind = 20;

          /* ADICIONA AS HORAS OU DIAS DE ACORDO COM O INDICE */
          Se (ind = 16)
          {
            xTotal = xTotal + 1;
            xTotHor = xTotHor + xHoras;
          }  
          Senao
          {
            Se (xdia > 1)
              xTotal = xTotal + 1;
          }

          }
        xind = xind + 1;
        }

      CMat.Proximo();
      }

    CMat.FecharCursor();

    /* OUTROS  */
    sql_abrcid = "";
    EstaNulo (EAbrOut, out_estanulo);
    Se (out_estanulo = 0)
      {
      MontaAbrangencia ("R110MAT.CODDOE", EAbrOut, sql_abrcid);
      sql_abrcid = " AND " + sql_abrcid;
      }
    Senao
      {
      EstaNulo (EAbrCid, cid_estanulo);
      Se (cid_estanulo = 0)
        {
        MontaAbrangencia ("R110MAT.CODDOE", EAbrCid, sql_abrcid);
        sql_abrcid = " AND NOT " + sql_abrcid;
        }
      }

    sql_abrcid = " AND " + lSQLWhere + sql_abrcid;   /* DATA REFERENCIA */

    CMat.SQL "SELECT CODDOE, HORAFA, HORTER FROM R110MAT WHERE DIAATE = :xdia __Inserir(:sql_abrcid) ORDER BY 2,1";
    CMat.AbrirCursor();

    Enquanto (CMat.Achou)
      {
      /* SE FOR APENAS 1 DIA, ENTAO CALCULA AS HORAS */
      Se (ind = 16)
        GetHoras (CMat.HorAfa, CMat.HorTer, xHoras);

      Se (ind < 16)
      {
        Se (xdia > 1)
          AddValor (lTotCid+1, xdia, 1);
      }
      Senao
        {     
          AddValor (lTotCid+1, 0, 1);
          TotalizaHoras(lTotCid+1, xHoras);
        }

      /* ADICIONA AS HORAS OU DIAS DE ACORDO COM O INDICE */
      Se (ind = 16)
      {
        xTotHor = xTotHor + xHoras;
        xTotal = xTotal + 1;
      }
      Senao
      {
        Se (xdia > 1)
          xTotal = xTotal + 1;
      }

      CMat.Proximo();
      }

    /* TOTAL DE AFASTAMENTOS NO DIA/HORA */
    Se (ind < 16)
    {
      Se (xdia > 1)
        AddValor (lTotCid+2, xdia, xTotal);
    }
    Senao
      {     
      AddValor (lTotCid+2, 0, xTotal);
      TotalizaHoras(lTotCid+2, xTotHor);
      }

    CMat.FecharCursor();
    }

  xTotal = 0;
  xTotHor = 0;
  xHoras = 0;
  /*********************************
          ATESTADOS EXTERNOS
   *********************************/
  sql_abrcid = " 1=1 ";
  IntParaAlfa (xdia, strdia);
  Se (EncMam = 1)
    {
    /* PROCURA PELOS CIDS A CONSIDERAR */
    EstaNulo (EAbrCid, cid_estanulo);
    Se (cid_estanulo = 0)
      MontaAbrangencia ("R110MAM.CODDOE", EAbrCid , sql_abrcid);

    sql_abrcid = " AND " + sql_abrcid;                 /* ABRANGENCIA          */
    sql_abrcid = " AND " + lSQLWhere + sql_abrcid;     /* DATA REFERENCIA      */
    Se (ind = 16)
      sql_abrcid = " AND TIPMAM = 1" + sql_abrcid;                    /* TEMPO DE AFASTAMENTO - HORAS */ 
    Senao
      sql_abrcid = " AND TIPMAM = 2 AND DIAATE = " + strdia + sql_abrcid; /* TEMPO DE AFASTAMENTO - DIAS */

    CMam.SQL "SELECT CODDOE, TIPMAM, DIAATE, HORAFA, HORTER, HORATE FROM R110MAM WHERE TIPASO = 0 AND ORIATE = 'E' __Inserir(:sql_abrcid) ORDER BY 2,1";
    CMam.AbrirCursor();

    /* ADICIONARA A TODOS OS CAMPOS OS DIAS DE AFASTAMENTO */
    Enquanto (CMam.Achou)
      {
      /* PROCURAR O CAMPO A SER INFORMADO */
      xind = 1;
      Enquanto (xind <= lTotCid)
        {
